INSERT INTO engine_bug_queue (bug_class, title, severity, owner_cluster, root_cause, prevention_rule, probe_type, probe_logic, status, concepts_affected, fixed_in_files, discovered_in_session, row_type) VALUES
('aha_statement_exceeds_15_words', 'aha_moment.statement authored >15 words; the validator rejects it (Gate 2)', 'MODERATE', 'alex:json_author', 'json_author wrote the aha as a full sentence; both circular_motion_charge_in_uniform_B and cyclotron_period_independent_of_speed first tripped the conceptJson.ts >15-word cap and had to be trimmed.', 'Author aha_moment.statement at <=15 words on the FIRST pass — it is a headline, not a sentence; the em-dash counts as its own token. Count words before emitting.', 'manual', 'npm run validate:concepts (conceptJson.ts superRefine ~L410) rejects an aha_moment.statement with >15 whitespace tokens.', 'FIXED', ARRAY['circular_motion_charge_in_uniform_B', 'cyclotron_period_independent_of_speed'], ARRAY['src/data/concepts/circular_motion_charge_in_uniform_B.json', 'src/data/concepts/cyclotron_period_independent_of_speed.json'], 'session_2026-06-25_radius_period_chain', 'incident'),
('cyclotron_start_marker_glyph_orphaned_from_orbit', 'STATE_2 same_start_marker yellow ring reads as an orphaned glyph near the slow/fast labels, not ON the orbit start point', 'MODERATE', 'peter_parker:renderer_primitives', 'The same_start_marker ring is drawn near the slow/fast text labels rather than sitting clearly ON the shared start point of the two orbits, so it reads as a stray decorative glyph (founder + auditor flagged it as a cosmetic on cyclotron_period STATE_2).', 'A decorative reference marker (start marker, tie marker) must sit ON its referent (the start point on the orbit ring), not float near text labels; co-locate it with the geometry it annotates.', 'manual', 'Inspect cyclotron_period STATE_2: the start marker sits on the shared orbit start point, not adrift near the slow/fast labels.', 'OPEN', ARRAY['cyclotron_period_independent_of_speed'], ARRAY[]::text[], 'session_2026-06-25_radius_period_chain', 'incident'),
('teach_read_dense_ramp_frames_not_just_frozen', 'THE EYE / reviewer must read DENSE frames across an in-state animation, not only the frozen end-state', 'MODERATE', 'peter_parker:visual_validator', 'The circular_motion ghost-compare spiral passed THE EYE deterministic gates, the frozen-frame review, AND the AI auditor — all three inspected only the END state; the live ramp was broken and only the founder watching the live sim caught it.', 'When a state animates within itself (ghost_compare ramp, sliders, equation_build, dual_orbit), read the DENSE frames across the transition window — a clean frozen end-state can hide a broken mid-transition.', 'manual', 'Visual-validator/reviewer: for any state with an in-state reveal/ramp, dense frames through the transition are read, not just the frozen frame.', 'OPEN', ARRAY['circular_motion_charge_in_uniform_B', 'cyclotron_period_independent_of_speed'], ARRAY[]::text[], 'session_2026-06-25_radius_period_chain', 'directive'),
('teach_inverted_scenario_inverts_cutline_flags', 'A new field_3d scenario that inverts a sibling must also invert its cut-line flags (never inherit the suppression of the quantity the new atom owns)', 'MODERATE', 'alex:architect', 'cyclotron_period inverts radius_in_uniform_field: #4 holds arc-speed constant and SUPPRESSES the period (hide_period_readout:true); #5 holds the period constant and must SURFACE it (show_period_readout:true). Blind-cloning the sibling would have inherited the suppression of the very quantity #5 teaches.', 'When a new field_3d scenario inverts what a sibling teaches, invert its cut-line flags too — surface the quantity the new atom owns; never inherit the sibling suppression flag.', 'manual', 'Architect/renderer: an inverted-sibling scenario flips the relevant hide_*/show_* cut-line flag for the quantity it now teaches.', 'OPEN', ARRAY['cyclotron_period_independent_of_speed'], ARRAY[]::text[], 'session_2026-06-25_radius_period_chain', 'directive'),
('teach_auditor_reads_field3d_sliders_from_config_not_scene_composition', 'For field_3d concepts the auditor must read the interactive control surface from field_3d_config / rendered frames, not from scene_composition placeholders', 'MODERATE', 'peter_parker:visual_validator', 'The quality-auditor nearly false-flagged cyclotron_period STATE_4 as having only a combined "m,q,B" slider by reading the JSON scene_composition placeholder primitives; the rendered reality is 4 independent cyc_* sliders driven by field_3d_config.', 'For field_3d concepts, judge the interactive control surface (sliders/knobs) from field_3d_config and the rendered frames, not from scene_composition placeholder primitives (which field_3d does not use for the actual controls).', 'manual', 'Auditor: slider/control claims for a field_3d state are sourced from field_3d_config + rendered frames, not scene_composition.', 'OPEN', ARRAY['cyclotron_period_independent_of_speed'], ARRAY[]::text[], 'session_2026-06-25_radius_period_chain', 'directive')
ON CONFLICT (bug_class) DO NOTHING;

